import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import copy from "copy-to-clipboard";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function EmployeeManagement() {
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    id: null,
    prefix: "Mr",
    name: "",
    email: "",
    phone: "",
    rolePermissionId: "",
    status: "Active",
    totalBalance: 0,
    commissionPercentage: "",
  });

  const [filters, setFilters] = useState({
    employeeSearch: "",
    status: "",
  });

  const [currentPage, setCurrentPage] = useState(1);
  const employeesPerPage = 10;

  const [detailsEmployee, setDetailsEmployee] = useState(null);

  const modalRef = useRef(null);
  const detailsModalRef = useRef(null);
  const navigate = useNavigate();

  /* ================= FETCH ================= */
  function fetchEmployees() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/employees", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((res) => {
        if (res.data.success) {
          setEmployees(res.data.data);
        } else {
          toast.error("Failed to fetch employees");
        }
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Error fetching employees"),
      )
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) navigate("/");
    else fetchEmployees();
  }, [navigate]);

  /* ================= INPUT CHANGE ================= */
  function handleInputChange(e) {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  }

  /* ================= FILTER CHANGE ================= */
  function handleFilterChange(e) {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
    setCurrentPage(1);
  }

  /* ================= ADD ================= */
  function openAddModal() {
    setFormData({
      id: null,
      prefix: "Mr",
      name: "",
      email: "",
      phone: "",
      rolePermissionId: "",
      status: "Active",
      totalBalance: 0,
      commissionPercentage: "",
    });

    const modalEl = document.getElementById("employeeModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  /* ================= EDIT ================= */
  function openEditModal(emp) {
    setFormData(emp);

    const modalEl = document.getElementById("employeeModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  /* ================= SUBMIT ================= */
  function handleSubmit(e) {
    e.preventDefault();
    const token = Cookies.get("adminToken");

    const payload = {
      ...formData,
      rolePermissionId: Number(formData.rolePermissionId),
    };

    const request = formData.id
      ? axios.put(API_BASE_URL + "/employees/" + formData.id, payload, {
          headers: { Authorization: "Bearer " + token },
        })
      : axios.post(API_BASE_URL + "/employees", payload, {
          headers: { Authorization: "Bearer " + token },
        });

    request
      .then(() => {
        toast.success(
          formData.id
            ? "Employee updated successfully"
            : "Employee created successfully",
        );
        fetchEmployees();
        modalRef.current.hide();
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Operation failed"),
      );
  }

  /* ================= FILTERED DATA ================= */
  const filteredEmployees = employees.filter((emp) => {
    const searchMatch = filters.employeeSearch
      ? (emp.name + emp.phone + emp.email + emp.role)
          .toLowerCase()
          .includes(filters.employeeSearch.toLowerCase())
      : true;

    return (
      searchMatch && (filters.status ? emp.status === filters.status : true)
    );
  });

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * employeesPerPage;
  const indexOfFirst = indexOfLast - employeesPerPage;
  const currentEmployees = filteredEmployees.slice(indexOfFirst, indexOfLast);
  const totalPages = Math.ceil(filteredEmployees.length / employeesPerPage);

  function goToNextPage() {
    if (currentPage < totalPages) setCurrentPage((prev) => prev + 1);
  }

  function goToPreviousPage() {
    if (currentPage > 1) setCurrentPage((prev) => prev - 1);
  }

  /* ================= COPY ================= */
  function handleCopy(text, type) {
    if (copy(text)) toast.success(type + " copied to clipboard");
    else toast.error("Failed to copy " + type);
  }

  /* ================= RM MODEL ================= */
  const [rmDetails, setRmDetails] = useState(null);
  const rmModalRef = useRef(null);

  function openRmModal(rm) {
    setRmDetails(rm);

    const modalEl = document.getElementById("rmModal");
    rmModalRef.current = new Modal(modalEl);
    rmModalRef.current.show();
  }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />

      {/* Back */}
      <div className="row mb-3">
        <div className="col">
          <i
            className="fa fa-arrow-left mt-2"
            style={{ cursor: "pointer" }}
            onClick={() => navigate("/dashboard")}
          ></i>
        </div>
      </div>

      {/* Header */}
      <div className="row g-3 mb-3">
        <div className="col-md-10 col-7">
          <h4 className="fw-bold mb-0">Employees</h4>
        </div>
        <div className="col-md-2 col-5 text-end">
          <button className="btn btn-primary btn-sm" onClick={openAddModal}>
            + Add Employee
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="row g-3 mb-3">
        <div className="col-md-6 col-6">
          <input
            type="text"
            name="employeeSearch"
            className="form-control form-control-sm"
            placeholder="Search (Name, Phone, Email, Role)"
            value={filters.employeeSearch}
            onChange={handleFilterChange}
          />
        </div>

        <div className="col-md-6 col-6">
          <select
            name="status"
            className="form-select form-select-sm"
            value={filters.status}
            onChange={handleFilterChange}
          >
            <option value="">Status</option>
            <option value="Active">Active</option>
            <option value="Inactive">Inactive</option>
          </select>
        </div>
      </div>

      {/* Applied Filters */}
      {(filters.employeeSearch || filters.status) && (
        <div className="row g-3 mb-3">
          <div className="col-auto">
            <span className="fw-semibold">Filters applied:</span>
          </div>

          {filters.employeeSearch && (
            <div className="col-auto">
              <span className="badge bg-secondary">
                Search: {filters.employeeSearch}
                <i
                  className="fa fa-times ms-1"
                  style={{ cursor: "pointer" }}
                  onClick={() =>
                    setFilters((prev) => ({ ...prev, employeeSearch: "" }))
                  }
                ></i>
              </span>
            </div>
          )}

          {filters.status && (
            <div className="col-auto">
              <span className="badge bg-secondary">
                Status: {filters.status}
                <i
                  className="fa fa-times ms-1"
                  style={{ cursor: "pointer" }}
                  onClick={() =>
                    setFilters((prev) => ({ ...prev, status: "" }))
                  }
                ></i>
              </span>
            </div>
          )}
        </div>
      )}

      {/* Table */}
      <div className="card mb-3">
        <div className="card border-0">
          {loading ? (
            <div className="text-center p-3">Loading...</div>
          ) : (
            <div className="table-responsive rounded">
              <table className="table table-striped table-hover mb-0 small">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>RM</th>
                    <th>Name</th>
                    <th>Contact</th>
                    <th>Role</th>
                    <th>Status</th>
                    <th>Balance</th>
                    <th>Date & Time</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {currentEmployees.map((emp) => (
                    <tr key={emp.id}>
                      <td>{emp.id}</td>
                      <td style={{ minWidth: "70px" }}>
                        {emp.rmId ? (
                          <i
                            className="fa-solid fa-user-tie text-info"
                            style={{ cursor: "pointer" }}
                            onClick={() =>
                              openRmModal({
                                id: emp.rmId,
                                prefix: emp.rmPrefix,
                                name: emp.rmName,
                                phone: emp.rmPhone,
                                email: emp.rmEmail,
                                role: emp.rmRole,
                                status: emp.rmStatus,
                              })
                            }
                          ></i>
                        ) : (
                          <span className="text-muted">N/A</span>
                        )}
                      </td>

                      <td style={{ minWidth: "180px" }}>
                        {emp.prefix} {emp.name}
                      </td>
                      <td style={{ minWidth: "130px" }}>
                        <i
                          className="fa-solid fa-phone text-success me-2"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleCopy(emp.phone, "Phone")}
                        ></i>
                        <i
                          className="fa-solid fa-envelope text-primary me-2"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleCopy(emp.email, "Email")}
                        ></i>
                        <i
                          className="fa-solid fa-id-card text-secondary"
                          style={{ cursor: "pointer" }}
                          onClick={() => {
                            setDetailsEmployee(emp);
                            const modalEl =
                              document.getElementById("detailsModal");
                            detailsModalRef.current = new Modal(modalEl);
                            detailsModalRef.current.show();
                          }}
                        ></i>
                      </td>
                      <td style={{ minWidth: "100px" }}>{emp.role}</td>
                      <td style={{ minWidth: "100px" }}>{emp.status}</td>
                      <td style={{ minWidth: "100px" }}>{emp.totalBalance}</td>
                      <td style={{ minWidth: "220px" }}>
                        <div className="d-flex flex-column">
                          <small>
                            <span className="fw-semibold text-muted">
                              Created:
                            </span>{" "}
                            {new Date(emp.createdAt).toLocaleString()}
                          </small>
                          <small>
                            <span className="fw-semibold text-muted">
                              Updated:
                            </span>{" "}
                            {new Date(emp.updatedAt).toLocaleString()}
                          </small>
                        </div>
                      </td>
                      <td>
                        <i
                          className="fa-solid fa-pen-to-square text-primary me-3"
                          style={{ cursor: "pointer" }}
                          onClick={() => openEditModal(emp)}
                        ></i>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      {/* Pagination */}
      <div className="d-flex justify-content-between align-items-center mb-3">
        <div>
          Page {currentPage} of {totalPages} • {filteredEmployees.length}{" "}
          records
        </div>
        <div>
          <button
            className="btn btn-sm border-0"
            disabled={currentPage === 1}
            onClick={goToPreviousPage}
          >
            <i className="fa-solid fa-chevron-left"></i>
          </button>
          <button
            className="btn btn-sm border-0"
            disabled={currentPage === totalPages || totalPages === 0}
            onClick={goToNextPage}
          >
            <i className="fa-solid fa-chevron-right"></i>
          </button>
        </div>
      </div>

      {/* Details Modal */}
      <div className="modal fade" id="detailsModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <div className="modal-header">
              <h5 className="modal-title">Employee Details</h5>
              <button
                type="button"
                className="btn-close"
                data-bs-dismiss="modal"
              ></button>
            </div>
            <div className="modal-body">
              {detailsEmployee && (
                <>
                  <p>
                    <strong>Phone:</strong> {detailsEmployee.phone}
                  </p>
                  <p>
                    <strong>Email:</strong> {detailsEmployee.email}
                  </p>
                </>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* RM Model */}
      <div className="modal fade" id="rmModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <div className="modal-header">
              <h5 className="modal-title">Relationship Manager Details</h5>
              <button
                type="button"
                className="btn-close"
                data-bs-dismiss="modal"
              ></button>
            </div>
            <div className="modal-body">
              {rmDetails && (
                <>
                  <p>
                    <strong>ID:</strong> {rmDetails.id}
                  </p>
                  <p>
                    <strong>Name:</strong> {rmDetails.prefix} {rmDetails.name}
                  </p>
                  <p>
                    <strong>Phone:</strong> {rmDetails.phone}
                  </p>
                  <p>
                    <strong>Email:</strong> {rmDetails.email}
                  </p>
                  <p>
                    <strong>Role:</strong> {rmDetails.role}
                  </p>
                  <p>
                    <strong>Status:</strong> {rmDetails.status}
                  </p>
                </>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Add/Edit Modal */}
<div className="modal fade" id="employeeModal" tabIndex="-1">
  <div className="modal-dialog modal-lg modal-dialog-centered">
    <div className="modal-content shadow-sm border-0">
      
      <div className="modal-header">
        <h5 className="modal-title">
          {formData.id ? "Edit Employee" : "Add Employee"}
        </h5>
        <button
          type="button"
          className="btn-close"
          data-bs-dismiss="modal"
        ></button>
      </div>

      <div className="modal-body">

        {/* ===== BASIC INFORMATION ===== */}
        <h6 className="fw-bold text-primary mb-3">
          Basic Information
        </h6>

        <div className="row g-3">

          <div className="col-md-2">
            <label className="form-label">Prefix</label>
            <select
              name="prefix"
              className="form-select"
              value={formData.prefix}
              onChange={handleInputChange}
            >
              <option>Mr</option>
              <option>Mrs</option>
              <option>Miss</option>
            </select>
          </div>

          <div className="col-md-4">
            <label className="form-label">
              Full Name <span className="text-danger">*</span>
            </label>
            <input
              type="text"
              name="name"
              className="form-control"
              value={formData.name}
              onChange={handleInputChange}
              required
            />
          </div>

          <div className="col-md-3">
            <label className="form-label">
              Email <span className="text-danger">*</span>
            </label>
            <input
              type="email"
              name="email"
              className="form-control"
              value={formData.email}
              onChange={handleInputChange}
              required
            />
          </div>

          <div className="col-md-3">
            <label className="form-label">
              Phone <span className="text-danger">*</span>
            </label>
            <input
              type="text"
              name="phone"
              className="form-control"
              value={formData.phone}
              onChange={handleInputChange}
              required
            />
          </div>

        </div>

        <hr className="my-4" />

        {/* ===== ROLE & STATUS ===== */}
        <h6 className="fw-bold text-primary mb-3">
          Role & Status
        </h6>

        <div className="row g-3">

          <div className="col-md-4">
            <label className="form-label">
              Role <span className="text-danger">*</span>
            </label>
            <select
              name="rolePermissionId"
              className="form-select"
              value={formData.rolePermissionId}
              onChange={handleInputChange}
              required
            >
              <option value="">Select Role</option>
              <option value="1">Admin</option>
              <option value="2">Broker</option>
              <option value="3">Accountant</option>
              <option value="4">Analyst</option>
            </select>
          </div>

          <div className="col-md-4">
            <label className="form-label">
              Status <span className="text-danger">*</span>
            </label>
            <select
              name="status"
              className="form-select"
              value={formData.status}
              onChange={handleInputChange}
              required
            >
              <option value="Active">Active</option>
              <option value="Inactive">Inactive</option>
            </select>
          </div>

        </div>

        <hr className="my-4" />

        {/* ===== FINANCIAL DETAILS ===== */}
        <h6 className="fw-bold text-primary mb-3">
          Financial Details
        </h6>

        <div className="row g-3">

          <div className="col-md-4">
            <label className="form-label">
              Commission Percentage (%)
            </label>
            <input
              type="number"
              name="commissionPercentage"
              className="form-control"
              value={formData.commissionPercentage}
              onChange={handleInputChange}
            />
          </div>

          <div className="col-md-4">
            <label className="form-label">
              Total Balance
            </label>
            <input
              type="number"
              name="totalBalance"
              className="form-control"
              value={formData.totalBalance}
              onChange={handleInputChange}
            />
          </div>

        </div>

      </div>

      <div className="modal-footer">
        <button
          type="button"
          className="btn btn-secondary"
          data-bs-dismiss="modal"
        >
          Cancel
        </button>

        <button
          type="button"
          className="btn btn-primary"
          onClick={handleSubmit}
        >
          {formData.id ? "Update Employee" : "Create Employee"}
        </button>
      </div>

    </div>
  </div>
</div>

    </div>
  );
}

export default EmployeeManagement;
